import{_ as a,o as l,c as i,a2 as o}from"./chunks/framework.BRk9mohw.js";const p=JSON.parse('{"title":"消息","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/messages.md","filePath":"concepts/messages.md"}'),t={name:"concepts/messages.md"};function r(s,e,c,d,n,h){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="消息" tabindex="-1">消息 <a class="header-anchor" href="#消息" aria-label="Permalink to &quot;消息&quot;">​</a></h1><h1 id="消息-1" tabindex="-1">消息 <a class="header-anchor" href="#消息-1" aria-label="Permalink to &quot;消息&quot;">​</a></h1><p>消息是 OpenClaw 与用户之间的通信单位。</p><h2 id="消息类型" tabindex="-1">消息类型 <a class="header-anchor" href="#消息类型" aria-label="Permalink to &quot;消息类型&quot;">​</a></h2><h3 id="入站消息" tabindex="-1">入站消息 <a class="header-anchor" href="#入站消息" aria-label="Permalink to &quot;入站消息&quot;">​</a></h3><p>来自渠道的用户消息：</p><ul><li>文本消息</li><li>媒体（图像、音频、视频、文档）</li><li>提及（@ 提及）</li><li>命令（斜杠命令）</li></ul><h3 id="出站消息" tabindex="-1">出站消息 <a class="header-anchor" href="#出站消息" aria-label="Permalink to &quot;出站消息&quot;">​</a></h3><p>代理的回复：</p><ul><li>文本回复</li><li>流式回复（实时输出）</li><li>工具结果</li><li>错误消息</li></ul><h2 id="消息属性" tabindex="-1">消息属性 <a class="header-anchor" href="#消息属性" aria-label="Permalink to &quot;消息属性&quot;">​</a></h2><ul><li><code>id</code>：唯一消息 ID</li><li><code>channel</code>：来源渠道</li><li><code>sender</code>：发送者身份</li><li><code>content</code>：消息内容</li><li><code>timestamp</code>：发送时间</li><li><code>attachments</code>：附加媒体</li></ul><h2 id="消息队列" tabindex="-1">消息队列 <a class="header-anchor" href="#消息队列" aria-label="Permalink to &quot;消息队列&quot;">​</a></h2><p>入站消息通过命令队列处理以防止冲突。参见<a href="/concepts/queue.html">队列</a>。</p><h2 id="消息钩子" tabindex="-1">消息钩子 <a class="header-anchor" href="#消息钩子" aria-label="Permalink to &quot;消息钩子&quot;">​</a></h2><p>消息生命周期钩子：</p><ul><li><code>message_received</code>：入站消息时调用</li><li><code>message_sending</code>：出站消息前调用</li><li><code>message_sent</code>：消息发送后调用</li></ul><p>参见<a href="/tools/plugin.html#plugin-hooks">插件钩子</a>。</p>',18)])])}const m=a(t,[["render",r]]);export{p as __pageData,m as default};
